import React from 'react';
import styled from 'styled-components';
import { StaticQuery, graphql } from 'gatsby';
import Img from 'gatsby-image';

import { Section, Container } from '@components/global';
import ExternalLink from '@common/ExternalLink';

const Footer = () => (
  <StaticQuery
    query={graphql`
      query {
        collabora: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "collabora" }
        ) {
          childImageSharp {
            fluid(maxWidth: 800) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
        linuxdevbr: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "linuxdev-br" }
        ) {
          childImageSharp {
            fluid(maxWidth: 800) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
        tux: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "tux" }
        ) {
          childImageSharp {
            fluid(maxWidth: 200) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
        mooks: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "gpsl-mooks" }
        ) {
          childImageSharp {
            fluid(maxWidth: 300) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
      }
    `}
    render={data => (
          <Grid>
            <div>
              <p>
          
              </p>
            </div>
            </Grid>
    )}
  />
);

const Grid = styled.div`
  grid-gap: 0px;
  text-align: center;
  align-items: center;
  justify-items: center;
  margin: 0 0;
  background-color: ${props => props.theme.color.primary};

  ${props =>
    props.inverse &&
    `
    text-align: left;
    grid-template-columns: 2fr 3fr;
  `}

  h2 {
    margin-bottom: 16px;
  }

  @media (max-width: ${props => props.theme.screen.md}) {
    grid-template-columns: 1fr;
    text-align: left;
    margin-bottom: 96px;

    &:last-child {
      margin-bottom: 24px;
    }

    ${props =>
      props.inverse &&
      `
        ${Art} {
          order: 2;
        }
    `}
  }
`;

const Art = styled.figure`
  margin: 0;
  max-width: 200px;
  width: 100%;
`;

export default Footer;
